from fractions import Fraction
class Solution:
    def eliminateMaximum(self, dist, speed):
        pairs = sorted(zip(dist, speed), key=lambda p: Fraction(p[0], p[1]))
        count = 0
        for i, (d, s) in enumerate(pairs):
            if d <= i * s:
                return count
            count += 1
        return count

