class Solution:
    def eliminateMaximum(self, dist, speed):
        pairs = sorted(zip(dist, speed), key=lambda p: p[0] / p[1])
        for i, (d, s) in enumerate(pairs):
            if d <= i * s:
                return i
        return len(dist)

