var eliminateMaximum = function(dist, speed) {
    const pairs = dist.map((d, i) => [d, speed[i]]).sort((a, b) => a[0] / a[1] - b[0] / b[1]);
    for (let i = 0; i < pairs.length; i++) {
        if (pairs[i][0] <= i * pairs[i][1]) return i;
    }
    return dist.length;
};
